Now, let's implement the game logic.

```python
class CheckersGame:
    def __init__(self):
        self.board = Board()

    def valid_moves(self, color):
        moves = []
        for row in range(8):
            for col in range(8):
                if self.board.board[row, col] == color:
                    moves.extend(self.valid_piece_moves(color, row, col))
        return moves

    def valid_piece_moves(self, color, row, col):
        moves = []
        directions = [(-1, -1), (-1, 1)] if color < 0 else [(1, -1), (1, 1)]
        for drow, dcol in directions:
            new_row, new_col = row + drow, col + dcol
            if self.is_valid_move(color, row, col, new_row, new_col):
                moves.append(((row, col), (new_row, new_col)))
        return moves

    def is_valid_move(self, color, start_row, start_col, end_row, end_col):
        if not ((0 <= end_row < 8 and 0 <= end_col < 8)):
            return False
        if self.board.board[end_row, end_col] != 0:
            return False

        directions = [(-1, -1), (-1, 1)] if color < 0 else [(1, -1), (1, 1)]
        for drow, dcol in directions:
            mid_row, mid_col = start_row + drow // 2, start_col + dcol // 2
            if ((start_row != mid_row or start_col != mid_col) and 
                self.is_capture(color, start_row, start_col, mid_row, mid_col, end_row, end_col)):
                return True

        return False

    def is_capture(self, color, start_row, start_col, mid_row, mid_col, end_row, end_col):
        if (self.board.board[mid_row, mid_col] != -color):
            return False
        if ((end_row == mid_row + drow or end_row == mid_row - drow) and 
            (end_col == mid_col + dcol or end_col == mid_col - dcol)):
            return True

        return False

    def move(self, start, end):
        piece = self.board.board[start[0], start[1]]
        capture_piece = self.board.board[end[0], end[1]]

        self.board.board[start[0], start[1]] = 0
        self.board.board[end[0], end[1]] = piece

        if abs(end[0] - start[0]) == 2:
            mid_row, mid_col = (start[0] + end[0]) // 2, (start[1] + end[1]) // 2
            self.board.board[mid_row, mid_col] = 0

        if piece == 1 and end[0] == 7 or piece == -1 and end[0] == 0:
            self.board.board[end[0], end[1]] = piece.king()

    def check_winner(self):
        white_pieces = np.sum(self.board.board > 0)
        black_pieces = np.sum(self.board.board < 0)

        if white_pieces == 0 or black_pieces == 0:
            return "White wins" if black_pieces == 0 else "Black wins"
        elif len(self.valid_moves(1)) == 0 and len(self.valid_moves(-1)) == 0:
            return "Draw"
        else:
            return None
